SELECT population
FROM provinces
WHERE province_name = (SELECT province FROM cases WHERE case_id = 0);

SELECT hospital_name
   FROM hospitals
   WHERE beds = (SELECT MAX(beds) FROM hospitals);

SELECT COUNT(DISTINCT patient_id) AS num_vaccinated_patients
FROM vaccinations
WHERE vaccine_type = 'Pfizer-BioNTech' AND vaccination_date < '2020-01-21';

SELECT COUNT(*)
FROM patients
WHERE age > 25 AND travel_history IS NOT NULL;
